import{_ as o,o as t,c as r,a2 as a}from"./chunks/framework.DvFsUg-r.js";const g=JSON.parse('{"title":"프론트엔드 첫 삽 — Spec Kit 한 바퀴, 그리고 \\"못 돌리는 코드\\"를 책임지는 법","description":"","frontmatter":{"slug":"frontend-mvp-spec-kit-cycle","title":"프론트엔드 첫 삽 — Spec Kit 한 바퀴, 그리고 \\"못 돌리는 코드\\"를 책임지는 법","authors":[],"tags":["spec-kit","sdd","vue","vuetify","frontend","pinia","migration"],"created":"2026-05-31 17:30 (KST)","date":"2026-05-31T08:30:00.000Z"},"headers":[],"relativePath":"journal/2026-05-31-frontend-mvp-spec-kit-cycle.md","filePath":"journal/2026-05-31-frontend-mvp-spec-kit-cycle.md","lastUpdated":1781092690000}'),c={name:"journal/2026-05-31-frontend-mvp-spec-kit-cycle.md"};function n(d,e,i,s,l,p){return t(),r("div",null,[...e[0]||(e[0]=[a('<p>&quot;플랫폼 이관이 다 끝났나?&quot;를 점검하다가 정작 <strong>프론트엔드가 없다</strong>는 걸 알았다. 004 는 22개 REST API + 데모 한 장이 전부였다. 그래서 feature 006(관리자 콘솔 SPA)을 <strong>Spec Kit 한 바퀴 — specify → clarify → plan → tasks → implement</strong> 로 한 세션에 돌리고, MVP 1차 (로그인·앱 셸)을 구현했다. 기록할 가치가 있는 건 구현 자체보다, <strong>이 환경에서 돌려볼 수 없는 프론트 코드를 어떻게 책임감 있게 짓느냐</strong>였다.</p><h2 id="spec-kit-한-바퀴" tabindex="-1">Spec Kit 한 바퀴 <a class="header-anchor" href="#spec-kit-한-바퀴" aria-label="Permalink to &quot;Spec Kit 한 바퀴&quot;">​</a></h2><ul><li><strong>specify</strong>: 22기능을 화면으로 다루는 관리자 콘솔. 백엔드 무변경(소비만).</li><li><strong>clarify</strong>: 네 가지를 확정 — MVP=<strong>FE1(셸·인증)+FE2(RBAC)</strong>, UI=<strong>Vuetify</strong>(lego 답습), 배포=<strong>Spring static 통합</strong>, i18n=<strong>후속</strong>(한국어 1차).</li><li><strong>plan</strong>: Version Lock 을 <code>C:/ax/lego</code> 의 검증된 조합(Vue 3.5·Vuetify 3.12·Vite 6· Pinia 3·TS 5.9)으로 고정. dev 는 별도 Vite server + <code>/api</code> 프록시, 배포는 <code>vite build</code> 산출물을 Spring <code>static/app</code> 으로.</li><li><strong>tasks</strong>: 52개(Setup→Foundational→US1~US7→Polish).</li><li><strong>implement</strong>: MVP 1차 = Setup + Foundational + US1.</li></ul><h2 id="진짜-문제-—-돌려볼-수-없는-코드" tabindex="-1">진짜 문제 — 돌려볼 수 없는 코드 <a class="header-anchor" href="#진짜-문제-—-돌려볼-수-없는-코드" aria-label="Permalink to &quot;진짜 문제 — 돌려볼 수 없는 코드&quot;">​</a></h2><p>이 작업 환경에는 네트워크가 없어 <code>npm install</code> 이 안 된다. 즉 <code>vite</code>, <code>vitest</code>, <code>vue-tsc</code> 를 <strong>한 번도 실행할 수 없다</strong>. 프론트 코드를 쓰지만 컴파일도, 테스트도 못 한다. 그럼 &quot;동작한다&quot;를 어떻게 책임지나? 세 가지 원칙으로 풀었다.</p><h3 id="_1-검증-가능한-경계는-끝까지-돌려본다" tabindex="-1">1. 검증 가능한 경계는 끝까지 돌려본다 <a class="header-anchor" href="#_1-검증-가능한-경계는-끝까지-돌려본다" aria-label="Permalink to &quot;1. 검증 가능한 경계는 끝까지 돌려본다&quot;">​</a></h3><p>이 기능에서 유일하게 돌려볼 수 있는 건 <strong>백엔드 통합분</strong>이다. SPA 딥링크(history 모드)는 <code>/app/users</code> 직접 진입 시 404 가 나므로, <code>SpaForwardController</code> 로 <code>/app/**</code>(확장자 없는 경로)를 <code>index.html</code> 로 forward 하고 SecurityConfig 에 <code>/app/**</code> 를 공개로 열었다. 이건 Java 라 <code>gradle :app:test</code> 로 검증된다 — <strong>28/28, 회귀 0</strong>. 프론트는 못 돌려도, 프론트를 받쳐주는 백엔드 한 조각은 초록으로 확인했다.</p><h3 id="_2-검증-가능한-것을-깨뜨릴-변경은-미룬다" tabindex="-1">2. 검증 가능한 것을 깨뜨릴 변경은 미룬다 <a class="header-anchor" href="#_2-검증-가능한-것을-깨뜨릴-변경은-미룬다" aria-label="Permalink to &quot;2. 검증 가능한 것을 깨뜨릴 변경은 미룬다&quot;">​</a></h3><p>plan 에는 &quot;Gradle node 플러그인으로 <code>gradle build</code> 가 <code>vite build</code> 를 자동 실행&quot; 이 있었다. 그런데 새 Gradle 플러그인을 추가하면 <strong>플러그인 해석 실패가 <code>gradle test</code> 까지 통째로 깨뜨릴 수 있다</strong> — 내가 유일하게 가진 검증 수단을. 그래서 자동 wiring 을 <strong>보류</strong>하고, 정적 통합은 <code>vite.config</code> 의 <code>outDir: static/app</code> 한 줄로만 달성했다(빌드는 <code>npm run build</code> 로 독립 수행). 원칙: <strong>검증 가능한 것을 깨뜨릴 위험이 있으면, 그 변경은 나중으로.</strong></p><h3 id="_3-못-돌리는-부분은-검증된-레퍼런스-에-기댄다" tabindex="-1">3. 못 돌리는 부분은 &quot;검증된 레퍼런스&quot;에 기댄다 <a class="header-anchor" href="#_3-못-돌리는-부분은-검증된-레퍼런스-에-기댄다" aria-label="Permalink to &quot;3. 못 돌리는 부분은 &quot;검증된 레퍼런스&quot;에 기댄다&quot;">​</a></h3><p>컴파일을 못 하니 버전 충돌·API 오용 위험이 크다. 그래서 스택 버전을 <strong><code>C:/ax/lego</code> 가 실제로 돌리는 조합 그대로</strong> 고정했다(헌법의 참조 출처 규약이 여기서 빛났다). 한 곳만 예외 — lego 의 <code>vue-router 5.0.3</code> 은 Vue 3 공식 라인(4.x)과 어긋나 보여, 그건 설치 시 호환 확인하도록 <code>^4.5.x</code> 로 두고 research 에 남겼다. &quot;검증 못 하면, 검증된 것을 베낀다.&quot;</p><h2 id="설계-메모-몇-개" tabindex="-1">설계 메모 몇 개 <a class="header-anchor" href="#설계-메모-몇-개" aria-label="Permalink to &quot;설계 메모 몇 개&quot;">​</a></h2><ul><li><strong>동적 메뉴</strong>: 네비는 <code>/menus/my</code> 트리로 그린다(권한 메뉴만 — SC-1). 메뉴 노드의 <code>path</code> 로 라우팅하고, 미구현 경로는 <code>NotFoundView</code>(&quot;준비 중&quot;)가 받는다.</li><li><strong>토큰</strong>: Access 는 메모리, refresh 토큰만 <code>localStorage</code> 에 둬 새로고침 시 <code>tryRestore</code> 로 세션을 복원한다(끊김 없는 세션 ↔ XSS 노출 최소화의 절충).</li><li><strong>순환 import 회피</strong>: <code>api/client.ts</code> 의 인터셉터가 <code>authStore</code>/<code>uiStore</code> 를 <strong>호출 시점에 동적 <code>import()</code></strong> 한다. 모듈 로드시 참조하지 않아 store↔client 순환을 끊었다.</li><li><strong>DataGrid</strong>: MVP 는 Vuetify <code>v-data-table-server</code>(소규모 RBAC 목록엔 충분). 대량(감사) 용 VuGrid 교체는 같은 컴포넌트 계약 뒤에 숨겨 후속으로.</li></ul><h2 id="지금" tabindex="-1">지금 <a class="header-anchor" href="#지금" aria-label="Permalink to &quot;지금&quot;">​</a></h2><p>MVP 1차는 &quot;로그인하면 권한 메뉴가 달린 셸까지&quot;. 실제로 화면이 뜨는지는 사용자 머신에서 <code>npm install &amp;&amp; npm run dev</code>(:5173) 로 확인하는 흐름이다 — 내가 못 돌린 마지막 한 걸음. 다음은 US2(사용자·역할·부서·메뉴 화면)로 MVP 를 완성한다.</p><blockquote><p>교훈: 돌려볼 수 없는 코드를 짓는 날도 있다. 그럴 땐 ① 돌릴 수 있는 경계는 끝까지 돌리고, ② 그 경계를 깨뜨릴 변경은 미루고, ③ 나머지는 검증된 레퍼런스에 기댄다.</p></blockquote>',16)])])}const h=o(c,[["render",n]]);export{g as __pageData,h as default};
